import{_ as e,o as r,c as d,ak as o}from"./chunks/framework.Bhye3ZK3.js";const b=JSON.parse('{"title":"高阶数据分析","description":"","frontmatter":{},"headers":[],"relativePath":"help/sakura/advanced.md","filePath":"doc/help/sakura/advanced.md"}'),p={name:"help/sakura/advanced.md"};function c(t,a,n,l,s,h){return r(),d("div",null,[...a[0]||(a[0]=[o('<h1 id="高阶数据分析" tabindex="-1">高阶数据分析 <a class="header-anchor" href="#高阶数据分析" aria-label="Permalink to “高阶数据分析”">​</a></h1><div class="warning custom-block github-alert"><p class="custom-block-title">数据要求</p><p>以下功能<strong>必须上传游戏数据</strong>才能使用。请先完成 <a href="./user-data#数据上传">数据上传</a>。</p></div><h2 id="排位与评分" tabindex="-1">排位与评分 <a class="header-anchor" href="#排位与评分" aria-label="Permalink to “排位与评分”">​</a></h2><h3 id="查看排位信息" tabindex="-1">查看排位信息 <a class="header-anchor" href="#查看排位信息" aria-label="Permalink to “查看排位信息”">​</a></h3><p><code>rk</code></p><p>获取玩家当前排位信息。</p><h3 id="b39-分析" tabindex="-1">B39 分析 <a class="header-anchor" href="#b39-分析" aria-label="Permalink to “B39 分析”">​</a></h3><p><code>b39</code></p><p>获取 Rating 最高的 39 首歌曲及总分（参考用）。</p><h3 id="b30-分析" tabindex="-1">B30 分析 <a class="header-anchor" href="#b30-分析" aria-label="Permalink to “B30 分析”">​</a></h3><p><code>pjsk b30</code></p><p>获取 Rating 最高的 30 首歌曲及平均分（算法不同）。</p><h2 id="歌曲进度查询" tabindex="-1">歌曲进度查询 <a class="header-anchor" href="#歌曲进度查询" aria-label="Permalink to “歌曲进度查询”">​</a></h2><h3 id="expert-进度" tabindex="-1">Expert 进度 <a class="header-anchor" href="#expert-进度" aria-label="Permalink to “Expert 进度”">​</a></h3><p><code>pjsk进度ex</code></p><p>查询 <strong>Expert</strong> 难度歌曲完成情况（AP/FC/Clear）。</p><h3 id="append-进度" tabindex="-1">Append 进度 <a class="header-anchor" href="#append-进度" aria-label="Permalink to “Append 进度”">​</a></h3><p><code>pjsk进度apd</code></p><p>查询 <strong>Append</strong> 难度歌曲完成情况。</p><h2 id="详细信息查询" tabindex="-1">详细信息查询 <a class="header-anchor" href="#详细信息查询" aria-label="Permalink to “详细信息查询”">​</a></h2><h3 id="个人详细信息" tabindex="-1">个人详细信息 <a class="header-anchor" href="#个人详细信息" aria-label="Permalink to “个人详细信息”">​</a></h3><p><code>pjskdetail</code></p><p>获取详细信息，包括金币、水晶、家具、每日挑战等。</p><blockquote><p>介意隐私者可私聊查询。</p></blockquote><h3 id="卡牌图鉴" tabindex="-1">卡牌图鉴 <a class="header-anchor" href="#卡牌图鉴" aria-label="Permalink to “卡牌图鉴”">​</a></h3><p><code>pjskcard</code></p><p>获取个人卡牌图鉴。</p><p><code>pjskcard+角色名</code></p><p>查指定角色的卡牌（如：<code>pjskcard+奏</code>）。</p><h3 id="活动历史" tabindex="-1">活动历史 <a class="header-anchor" href="#活动历史" aria-label="Permalink to “活动历史”">​</a></h3><p><code>pjskevent</code></p><p>获取个人历史最高活动排名记录（近 10 次）。</p><h2 id="多服支持" tabindex="-1">多服支持 <a class="header-anchor" href="#多服支持" aria-label="Permalink to “多服支持”">​</a></h2><p>所有指令都支持多服前缀：</p><p><strong>日服（默认）</strong></p><p><code>rk</code> / <code>b39</code></p><p><strong>台服</strong></p><p><code>twrk</code> / <code>twb39</code></p><p><strong>国服</strong></p><p><code>cnrk</code> / <code>cnb39</code></p>',40)])])}const k=e(p,[["render",c]]);export{b as __pageData,k as default};
